import logging
from typing import Set, List, Optional, Iterable

import numpy as np
import osmapi
from geosat.cloud import PointCloud
from geosat.psanp.abstractions.classifier import Classifier
from geosat.psanp.abstractions.option import Option
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata
from matplotlib.path import Path
from pyproj import Proj, transform
from shapely.geometry import Polygon

logger = logging.getLogger(__name__)


class CadastreClassifier(Classifier):
    """
    Load building polygon data from OSM and classify the cloud accordingly
    """

    def __init__(
        self,
        projection="EPSG:4326",
        margin=0.5,
        blacklist=(),
        stage_name: Optional[str] = None,
    ):
        super().__init__(stage_name)
        self.is_trained = True
        self.blacklist = blacklist
        self.projection = projection
        self.margin = margin
        self.output_class = "building"

    def input_classes(self) -> Set[str]:
        return set()

    def output_classes(self) -> Set[str]:
        return {self.output_class}

    @classmethod
    def options(cls) -> List[Option]:
        # TODO: The projection should be in the cloud/pipeline metadata
        return [
            Option(
                "projection",
                "EPSG code of the project the cloud is in",
                type_cast=str,
                required=True,
            ),
            Option("margin", "", type_cast=float, required=False),
            Option("blacklist", "", type_cast=list, required=False),
        ]

    def _classify_subset(self, points, buildings):
        is_in_building = np.zeros(len(points), dtype=bool)
        logger.info("{} building(s) found".format(len(buildings)))
        for index, building in enumerate(buildings, 1):
            logger.debug("Processing building {}".format(index))
            polygon = Path(building.buffer(self.margin, join_style=2).exterior)
            # Optimization
            minimum = np.min(polygon.vertices, axis=0)
            maximum = np.max(polygon.vertices, axis=0)
            mask = np.all(np.logical_and(points >= minimum, points <= maximum), axis=1)
            is_in_building[mask] |= polygon.contains_points(points[mask])
        return is_in_building

    def execute_on(
        self, cloud: PointCloud, pipeline_metadata: PipelineMetadata
    ) -> Iterable[PointCloud]:
        if not cloud:
            return (cloud,)
        buildings = [
            Polygon(points)
            for points in load_osm_geometries(
                cloud.bb_min()[:2], cloud.bb_max()[:2], "building", self.projection
            )
        ]
        blacklist = [
            pipeline_metadata.classification_codes[input_class]
            for input_class in self.blacklist
        ]
        is_input_class = ~np.isin(cloud.classification, blacklist)
        is_in_building = self._classify_subset(
            cloud.coords[:, :2][is_input_class], buildings
        )
        to_modify = np.zeros_like(is_input_class)
        to_modify[is_input_class] = is_in_building
        cloud.classification[to_modify] = pipeline_metadata.classification_codes[
            self.output_class
        ]

        return (cloud,)


def is_osm_entity(osm_result, entity_name):
    try:
        return (
            osm_result["data"]["tag"][entity_name] == "yes"
            and "nd" in osm_result["data"]
        )
    except KeyError:
        return False


def load_osm_geometries(bb_min, bb_max, osm_name, projection="EPSG:4326"):
    osm = osmapi.OsmApi()
    local = Proj(projection)
    gps = Proj("EPSG:4326")
    minimum = transform(local, gps, *bb_min)
    maximum = transform(local, gps, *bb_max)
    results = osm.Map(*minimum, *maximum)
    osm_entities = [result for result in results if is_osm_entity(result, osm_name)]
    geometries = []
    for osm_entity in osm_entities:
        identifiers = osm_entity["data"]["nd"]
        nodes = osm.NodesGet(identifiers)
        geometries.append(
            [
                transform(gps, local, node["lon"], node["lat"])
                for node in (nodes[identifier] for identifier in identifiers)
            ]
        )
    return geometries
